Example 2-3: Solution
Prepare data

mpg_data &lt;- c(12,17,12,14,16,18,16,18,12,16,
              15,15,16,12,15,15,16,16,12,14,
              15,12,15,15,12,16,15,16,16,12)

Draw the figure

ungrouped &lt;- data.frame(mpg_data) |&gt;
  count(mpg_data) |&gt;
  rename(MPG = mpg_data, Frequency = n) |&gt;
  mutate(
    `Rel. Freq.` = round(Frequency / sum(Frequency), 3),
    `Cum. Freq.` = cumsum(Frequency)
  )

Example 2-9: Solution

homeless &lt;- data.frame(
  city  = c("Atlanta","Chicago","Washington\nD.C.","Baltimore","St. Louis"),
  count = c(6832, 6680, 5518, 2904, 1485)
) |&gt;
  arrange(desc(count)) |&gt;
  mutate(city = factor(city, levels = city))
